    fp rcn4B = k4Bon*Ca4CaM*B - k4Boff*Ca4CaMB;

    fp Ca2CaN = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN;
    fp rcnCa4CaN = kcanCaon*pow(Ca,2)*Ca2CaN - kcanCaoff*Ca4CaN;
    fp rcn02CaN = k02can*pow(Ca,2)*CaMCa4CaN - k20can*Ca2CaMCa4CaN;
    fp rcn24CaN = k24can*pow(Ca,2)*Ca2CaMCa4CaN - k42can*Ca4CaMCa4CaN;
    fp rcn0CaN = kcanCaM0on*CaM*Ca4CaN - kcanCaM0off*CaMCa4CaN;
    fp rcn2CaN = kcanCaM2on*Ca2CaM*Ca4CaN - kcanCaM2off*Ca2CaMCa4CaN;
    fp rcn4CaN = kcanCaM4on*Ca4CaM*Ca4CaN - kcanCaM4off*Ca4CaMCa4CaN;

    fp Pix = 1.0f - Pb2 - Pb - Pt - Pt2 - Pa;
    fp rcnCKib2 = kib2*Ca2CaM*Pix - kb2i*Pb2;
    fp rcnCKb2b = kb24*pow(Ca,2)*Pb2 - kb42*Pb;
    fp rcnCKib = kib*Ca4CaM*Pix - kbi*Pb;
    fp T = Pb + Pt + Pt2 + Pa;
    fp kbt = 0.055f*T + 0.0074f*pow(T,2) + 0.015f*pow(T,3);
    fp rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt);
    fp rcnCKtt2 = kt42*Pt - kt24*pow(Ca,2)*Pt2;
    fp rcnCKta = kta*Pt - kat*Ca4CaM*Pa;
    fp rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa;
    fp rcnCKt2b2 = kpp1*PP1tot*Pt2/(Kmpp1+CaMKIItot*Pt2);
    fp rcnCKai = kpp1*PP1tot*Pa/(Kmpp1+CaMKIItot*Pa);

    fp dCaM = 1e-3f*(-rcn02 - rcn0B - rcn0CaN);
    fp dCa2CaM = 1e-3f*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a));
    fp dCa4CaM = 1e-3f*(rcn24 - rcn4B - rcn4CaN + CaMKIItot*(-rcnCKib + rcnCKta));
    fp dCaMB = 1e-3f*(rcn0B - rcn02B);
    fp dCa2CaMB = 1e-3f*(rcn02B + rcn2B - rcn24B);
    fp dCa4CaMB = 1e-3f*(rcn24B + rcn4B);

    fp dPb2 = 1e-3f*(rcnCKib2 - rcnCKb2b + rcnCKt2b2);
    fp dPb = 1e-3f*(rcnCKib + rcnCKb2b - rcnCKbt);
    fp dPt = 1e-3f*(rcnCKbt - rcnCKta - rcnCKtt2);
    fp dPt2 = 1e-3f*(rcnCKtt2 - rcnCKt2a - rcnCKt2b2);
    fp dPa = 1e-3f*(rcnCKta + rcnCKt2a - rcnCKai);

    fp dCa4CaN = 1e-3f*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN);
    fp dCaMCa4CaN = 1e-3f*(rcn0CaN - rcn02CaN);
    fp dCa2CaMCa4CaN = 1e-3f*(rcn2CaN + rcn02CaN - rcn24CaN);
    fp dCa4CaMCa4CaN = 1e-3f*(rcn4CaN + rcn24CaN);

    d_finavalu[offset_1] = dCaM;
    d_finavalu[offset_2] = dCa2CaM;
    d_finavalu[offset_3] = dCa4CaM;
    d_finavalu[offset_4] = dCaMB;
    d_finavalu[offset_5] = dCa2CaMB;
    d_finavalu[offset_6] = dCa4CaMB;
    d_finavalu[offset_7] = dPb2;
    d_finavalu[offset_8] = dPb;
    d_finavalu[offset_9] = dPt;
    d_finavalu[offset_10] = dPt2;
    d_finavalu[offset_11] = dPa;
    d_finavalu[offset_12] = dCa4CaN;
    d_finavalu[offset_13] = dCaMCa4CaN;
    d_finavalu[offset_14] = dCa2CaMCa4CaN;
    d_finavalu[offset_15] = dCa4CaMCa4CaN;

    d_finavalu[com_offset] = 1e-3f*(2.0f*CaMKIItot*(rcnCKtt2 - rcnCKb2b) - 2.0f*(rcn02 + rcn24 + rcn02B + rcn24B + rcnCa4CaN + rcn02CaN + rcn24CaN));
}

__kernel void kernel_2(
    int timeinst,
    __global fp* initvalu,
    __global fp* params,
    __global fp* finavalu,
    __global fp* com)
{
    int valu_offset_ecc = 0;
    int valu_offset_Dyad = 46;
    int valu_offset_SL = 61;
    int valu_offset_Cyt = 76;

    int params_offset_Dyad = 0;
    int params_offset_SL = 5;
    int params_offset_Cyt = 10;

    int com_offset_Dyad = 0;
    int com_offset_SL = 1;
    int com_offset_Cyt = 2;

    kernel_ecc_2(timeinst, initvalu, finavalu, valu_offset_ecc, params);

    fp CaDyad = initvalu[35]*1e3f;
    kernel_cam_2(timeinst, initvalu, finavalu, valu_offset_Dyad, params, params_offset_Dyad, com, com_offset_Dyad, CaDyad);

    fp CaSL = initvalu[36]*1e3f;
    kernel_cam_2(timeinst, initvalu, finavalu, valu_offset_SL, params, params_offset_SL, com, com_offset_SL, CaSL);

    fp CaCyt = initvalu[37]*1e3f;
    kernel_cam_2(timeinst, initvalu, finavalu, valu_offset_Cyt, params, params_offset_Cyt, com, com_offset_Cyt, CaCyt);

    kernel_fin_2(timeinst, initvalu, finavalu, valu_offset_ecc, valu_offset_Dyad, valu_offset_SL, valu_offset_Cyt, params, com);

    for (int i = 0; i < EQUATIONS; i++) {
        if (isnan(finavalu[i]) || isinf(finavalu[i])) {
            finavalu[i] = 0.0001f;
        }
    }
}
